#include <bits/stdc++.h>
using namespace std;
struct Node {
    int key, value;
    Node* prev;
    Node* next;
    Node(int k, int v) : key(k), value(v), prev(nullptr), next(nullptr) {}
};
class LRUCache {
private:
    int capacity;
    unordered_map<int, Node*> cache;
    Node* head;
    Node* tail;
public:
    LRUCache(int capacity) : capacity(capacity) {
        head = new Node(0, 0);
        tail = new Node(0, 0);
        head->next = tail;
        tail->prev = head;
    }
    ~LRUCache() {
        while (head->next != tail) {
            Node* node = head->next;
            head->next = node->next;
            node->next->prev = head;
            delete node;
        }
        delete head;
        delete tail;
    }
    int get(int key) {
        if (cache.find(key) != cache.end()) {
            Node* node = cache[key];
            remove(node);
            add(node);
            return node->value;
        }
        return -1;
    }
    void put(int key, int value) {
        if (cache.find(key) != cache.end()) {
            Node* node = cache[key];
            node->value = value;
            remove(node);
            add(node);
        } else {
            if (cache.size() == capacity) {
                Node* lru = tail->prev;
                remove(lru);
                cache.erase(lru->key);
                delete lru;
            }
            Node* node = new Node(key, value);
            add(node);
            cache[key] = node;
        }
    }
    void remove(Node* node) {
        node->prev->next = node->next;
        node->next->prev = node->prev;
    }
    void add(Node* node) {
        node->prev = head;
        node->next = head->next;
        head->next->prev = node;
        head->next = node;
    }
};
int main() {
    int capacity, operations;
    cin >> capacity >> operations;
    LRUCache cache(capacity);
    for (int i = 0; i < operations; i++) {
        string op;
        cin >> op;
        if (op == "get") {
            int key;
            cin >> key;
            cout << cache.get(key) << endl;
        } else if (op == "put") {
            int key, value;
            cin >> key >> value;
            cache.put(key, value);
        }
    }
    return 0;
}
